const CartPage = ({ 
  cart, 
  updateQuantity, 
  removeFromCart, 
  onCheckout 
}: { 
  cart: CartItem[]; 
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  onCheckout: () => void;
}) => {
  const subtotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const shipping = subtotal > 50 ? 0 : 5.99;

  if (cart.length === 0) {
    return (
      <div className="pt-32 pb-20 px-4 text-center max-w-xl mx-auto animate-in fade-in zoom-in-95 duration-500">
