                      className="text-gray-500 hover:text-pink-600 transition-colors"
                    >
                      <Plus size={16} />
                    </button>
                  </div>
                  <p className="font-bold text-pink-600">${(item.price * item.quantity).toFixed(2)}</p>
                </div>
              </div>
