const CheckoutPage = ({ cart, onBack }: { cart: CartItem[]; onBack: () => void }) => {
  const [step, setStep] = useState<'details' | 'payment'>('details');
  const [method, setMethod] = useState<'transfer' | 'whatsapp'>('transfer');

  const subtotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const total = subtotal > 50 ? subtotal : subtotal + 5.99;

  const orderSummaryText = cart.map(i => `${i.name} x${i.quantity}`).join(', ');
  const whatsappUrl = `https://wa.me/234000000000?text=${encodeURIComponent(
