const App = () => {
  const [currentPath, setCurrentPath] = useState('home');
  const [cart, setCart] = useState<CartItem[]>([]);

  // Persist cart
  useEffect(() => {
    const saved = localStorage.getItem('maygloss_cart');
    if (saved) setCart(JSON.parse(saved));
  }, []);

  useEffect(() => {
    localStorage.setItem('maygloss_cart', JSON.stringify(cart));
  }, [cart]);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === product.id);
      if (existing) {
        return prev.map(i => i.id === product.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    // Optional toast notification
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(i => {
      if (i.id === id) {
        const newQty = Math.max(1, i.quantity + delta);
        return { ...i, quantity: newQty };
      }
      return i;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(i => i.id !== id));
  };

  const cartCount = cart.reduce((sum, i) => sum + i.quantity, 0);

  const renderContent = () => {
    switch (currentPath) {
      case 'home': return <HomePage onNavigate={setCurrentPath} addToCart={addToCart} />;
      case 'products': return <ProductsPage addToCart={addToCart} />;
      case 'contact': return <ContactPage />;
      case 'cart': return (
        <CartPage 
          cart={cart} 
          updateQuantity={updateQuantity} 
          removeFromCart={removeFromCart} 
          onCheckout={() => setCurrentPath('checkout')} 
        />
      );
      case 'checkout': return <CheckoutPage cart={cart} onBack={() => setCurrentPath('cart')} />;
      default: return <HomePage onNavigate={setCurrentPath} addToCart={addToCart} />;
    }
  };

  // Scroll to top on page change
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [currentPath]);

  return (
    <div className="min-h-screen bg-white text-gray-900 font-sans selection:bg-pink-100 selection:text-pink-600">
      <Navbar 
        cartCount={cartCount} 
        onNavigate={setCurrentPath} 
        currentPath={currentPath} 
      />
      <main className="min-h-[80vh]">
        {renderContent()}
      </main>
      <Footer />
    </div>
  );
};

const container = document.getElementById('root');
const root = createRoot(container!);
root.render(<App />);

