// --- App Root ---

const App = () => {
  const [currentPath, setCurrentPath] = useState('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [darkMode, setDarkMode] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);

  // Initialize Theme
  useEffect(() => {
    const isDark = localStorage.getItem('maygloss_theme') === 'dark';
    setDarkMode(isDark);
  }, []);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('maygloss_theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('maygloss_theme', 'light');
    }
  }, [darkMode]);

  // Persist cart
  useEffect(() => {
    const saved = localStorage.getItem('maygloss_cart');
    if (saved) setCart(JSON.parse(saved));
  }, []);

  useEffect(() => {
    localStorage.setItem('maygloss_cart', JSON.stringify(cart));
  }, [cart]);

  const addToCart = (product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === product.id);
      if (existing) {
        return prev.map(i => i.id === product.id ? { ...i, quantity: i.quantity + quantity } : i);
      }
      return [...prev, { ...product, quantity }];
    });
    // Move to cart page to show user it worked
    setCurrentPath('cart');
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(i => {
      if (i.id === id) {
        const newQty = Math.max(1, i.quantity + delta);
        return { ...i, quantity: newQty };
      }
      return i;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(i => i.id !== id));
  };

  const onViewProduct = (p: Product) => {
    setSelectedProduct(p);
    setCurrentPath('product-detail');
  };

  const cartCount = cart.reduce((sum, i) => sum + i.quantity, 0);

  const renderContent = () => {
    switch (currentPath) {
      case 'home': return <HomePage onNavigate={setCurrentPath} addToCart={addToCart} onViewProduct={onViewProduct} />;
      case 'products': return <ProductsPage addToCart={addToCart} onViewProduct={onViewProduct} searchQuery={searchQuery} />;
      case 'product-detail': return selectedProduct ? (
        <ProductDetailPage 
          product={selectedProduct} 
          onBack={() => setCurrentPath('products')} 
          addToCart={addToCart} 
        />
      ) : <HomePage onNavigate={setCurrentPath} addToCart={addToCart} onViewProduct={onViewProduct} />;
      case 'contact': return <ContactPage />;
      case 'cart': return (
        <CartPage 
          cart={cart} 
          updateQuantity={updateQuantity} 
          removeFromCart={removeFromCart} 
          onCheckout={() => setCurrentPath('checkout')} 
        />
      );
      case 'checkout': return <CheckoutPage cart={cart} onBack={() => setCurrentPath('cart')} />;
      default: return <HomePage onNavigate={setCurrentPath} addToCart={addToCart} onViewProduct={onViewProduct} />;
    }
  };

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [currentPath]);

  return (
    <div className="min-h-screen bg-white dark:bg-slate-950 text-gray-900 dark:text-gray-100 font-sans transition-colors duration-300">
      <Navbar 
        cartCount={cartCount} 
        onNavigate={setCurrentPath} 
        currentPath={currentPath} 
        darkMode={darkMode}
        toggleDarkMode={() => setDarkMode(!darkMode)}
        searchQuery={searchQuery}
        setSearchQuery={setSearchQuery}
      />
      <main className="min-h-[80vh]">
        {renderContent()}
      </main>
      <Footer />
    </div>
  );
};

