const ProductsPage = ({ addToCart, onViewProduct, searchQuery }: any) => {
  const [category, setCategory] = useState('All');
  const categories = ['All', 'Shine', 'Matte', 'Plumper', 'Tint'];

  const list = useMemo(() => {
    let result = PRODUCTS;
    if (category !== 'All') result = result.filter(p => p.category === category);
    if (searchQuery) {
      result = result.filter(p => p.name.toLowerCase().includes(searchQuery.toLowerCase()));
    }
    return result;
  }, [category, searchQuery]);

  return (
    <div className="pt-32 pb-32 px-4 max-w-7xl mx-auto bg-white dark:bg-slate-950 transition-colors">
      <div className="text-center mb-20">
        <h1 className="text-5xl font-serif font-bold text-indigo-950 dark:text-white mb-8">The Collection</h1>
        <div className="flex flex-wrap justify-center gap-3">
          {categories.map(cat => (
            <button
              key={cat}
              onClick={() => setCategory(cat)}
              className={`px-8 py-2.5 rounded-full text-[10px] font-bold uppercase tracking-widest transition-all ${
                category === cat 
                ? 'bg-indigo-950 text-white shadow-xl' 
                : 'bg-slate-50 dark:bg-slate-900 text-slate-500 border border-transparent hover:border-purple-200'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-x-8 gap-y-16">
        {list.map(product => (
          <ProductCard 
            key={product.id} 
            product={product} 
            addToCart={addToCart} 
            onViewProduct={onViewProduct} 
          />
        ))}
      </div>
      {list.length === 0 && (
        <div className="text-center py-40">
          <p className="text-slate-400 italic">No shades found matching "{searchQuery}"</p>
        </div>
      )}
    </div>
  );
};

