      default: return <HomePage onNavigate={setCurrentPath} addToCart={addToCart} onViewProduct={openProductModal} />;
    }
  };

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [currentPath]);

  return (
    <div className="min-h-screen bg-white dark:bg-slate-950 text-slate-900 dark:text-slate-100 font-sans transition-colors duration-500">
      <Navbar 
        cartCount={cartCount} 
