      />
      <main className="min-h-screen pt-20">
        {renderContent()}
      </main>
      <Footer />

      <ScrollToTop />

      <AnimatePresence>
        {isModalOpen && selectedProduct && (
          <ProductModal 
            product={selectedProduct} 
            onClose={() => setIsModalOpen(false)} 
            addToCart={addToCart} 
          />
        )}
      </AnimatePresence>
