                    <span className="text-xs font-bold uppercase tracking-widest text-indigo-950">Shop Best Sellers</span>
                </label>
            </div>
        </div>

        {/* Product Grid */}
        <div className="flex-grow">
            <div className="grid grid-cols-2 lg:grid-cols-3 gap-x-8 gap-y-16">
                {list.map(product => (
                <ProductCard 
                    key={product.id} 
