            <button onClick={() => setMethod('whatsapp')} className={`w-full p-6 rounded-3xl border text-left flex justify-between items-center transition-all ${method === 'whatsapp' ? 'border-green-600 bg-green-50/30' : 'border-slate-100'}`}>
