                </div>
                <button onClick={handleComplete} className="w-full bg-indigo-950 text-white py-5 rounded-full font-bold mt-10 text-[10px] tracking-widest uppercase flex items-center justify-center gap-3">
                    {isProcessing ? <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1, ease: "linear" }}><Loader2 size={16} /></motion.div> : "Confirm Payment"}
                </button>
              </motion.div>
            ) : (
              <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -10 }} key="whatsapp" className="p-10 bg-green-50 rounded-[2.5rem] border border-green-100 shadow-xl">
