// --- Root Component ---

const App = () => {
  const [currentPath, setCurrentPath] = useState('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [darkMode, setDarkMode] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [addingToCartId, setAddingToCartId] = useState<string | null>(null);
  const [isNavigating, setIsNavigating] = useState(false);

  useEffect(() => {
    const isDark = localStorage.getItem('maygloss_theme') === 'dark';
    setDarkMode(isDark);
  }, []);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('maygloss_theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('maygloss_theme', 'light');
    }
  }, [darkMode]);

  useEffect(() => {
    const saved = localStorage.getItem('maygloss_cart');
    if (saved) setCart(JSON.parse(saved));
  }, []);

  useEffect(() => {
    localStorage.setItem('maygloss_cart', JSON.stringify(cart));
  }, [cart]);

  const addNotification = useCallback((message: string, type: 'success' | 'error' | 'info' = 'success') => {
    const id = Math.random().toString(36).substr(2, 9);
    setNotifications(prev => [...prev, { id, message, type }]);
    setTimeout(() => {
      setNotifications(prev => prev.filter(n => n.id !== id));
    }, 4000);
  }, []);

  const removeNotification = useCallback((id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  }, []);

  const navigateTo = (path: string) => {
    setIsNavigating(true);
    setTimeout(() => {
      setCurrentPath(path);
      setIsNavigating(false);
    }, 500); // Artificial nav delay for loading visibility
  };

  const addToCart = (product: Product) => {
    setAddingToCartId(product.id);
    setTimeout(() => {
        setCart(prev => {
            const existing = prev.find(i => i.id === product.id);
            if (existing) return prev.map(i => i.id === product.id ? { ...i, quantity: i.quantity + 1 } : i);
            return [...prev, { ...product, quantity: 1 }];
        });
        setAddingToCartId(null);
        addNotification(`${product.name} added to bag!`, 'success');
    }, 600);
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(i => i.id === id ? { ...i, quantity: Math.max(1, i.quantity + delta) } : i));
  };

  const removeFromCart = (id: string) => {
    const item = cart.find(i => i.id === id);
    setCart(prev => prev.filter(i => i.id !== id));
    if(item) addNotification(`Removed ${item.name} from bag.`, 'info');
  };

  const cartCount = cart.reduce((sum, i) => sum + i.quantity, 0);

  const renderContent = () => {
    if(isNavigating) return (
        <div className="min-h-[70vh] flex items-center justify-center">
            <LoadingSpinner text="Preparing Radiance..." />
        </div>
    );

    switch (currentPath) {
      case 'home': return <HomePage onNavigate={navigateTo} addToCart={addToCart} addingId={addingToCartId} />;
      case 'products': return <ProductsPage addToCart={addToCart} searchQuery={searchQuery} addingId={addingToCartId} />;
      case 'lookbook': return <LookbookPage />;
      case 'story': return <StoryPage />;
      case 'contact': return <ContactPage />;
      case 'cart': return <CartPage cart={cart} updateQuantity={updateQuantity} removeFromCart={removeFromCart} onCheckout={() => navigateTo('checkout')} />;
      case 'checkout': return <CheckoutPage cart={cart} onBack={() => navigateTo('cart')} onComplete={() => { setCart([]); navigateTo('home'); addNotification('Order confirmed! Check WhatsApp for tracking.', 'success'); }} />;
      default: return <HomePage onNavigate={navigateTo} addToCart={addToCart} addingId={addingToCartId} />;
    }
  };

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [currentPath]);

  return (
    <div className="min-h-screen bg-white dark:bg-slate-950 text-slate-900 dark:text-slate-100 font-sans transition-colors duration-500">
      <Navbar 
        cartCount={cartCount} 
        onNavigate={navigateTo} 
        currentPath={currentPath} 
        darkMode={darkMode}
        toggleDarkMode={() => { setDarkMode(!darkMode); addNotification(`Theme switched to ${!darkMode ? 'dark' : 'light'} mode.`, 'info'); }}
        searchQuery={searchQuery}
        setSearchQuery={setSearchQuery}
      />
      <main className="min-h-screen pt-20">
        <AnimatePresence mode="wait">
            <motion.div
                key={currentPath + (isNavigating ? 'loading' : 'content')}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                transition={{ duration: 0.3 }}
            >
                {renderContent()}
            </motion.div>
        </AnimatePresence>
      </main>
      <Footer onNavigate={navigateTo} />

      <ScrollToTop />

      <NotificationToast notifications={notifications} remove={removeNotification} />
    </div>
  );
};

const container = document.getElementById('root');
const root = createRoot(container!);
root.render(<App />);

