        <div className="grid grid-cols-1 md:grid-cols-3 gap-12">
          {PRODUCTS.filter(p => p.id !== product.id).slice(0, 3).map(p => (
             <ProductCard 
                key={p.id} 
                product={p} 
                addToCart={(prod) => addToCart(prod, 1)} 
                isAdding={addingId === p.id} 
