        </div>
      );
      case 'consultant': return <AIConsultant />;
      case 'story': return <LegalPage title="Botanical Passion" content={<StoryContent />} />;
      case 'faq': return <LegalPage title="Beauty Enquiries" content={<FAQContent />} />;
      case 'cart': return (
