          {cart.length === 0 ? (
            <div className="text-center py-24 bg-white dark:bg-slate-900 rounded-[3.5rem] shadow-sm border border-slate-50 dark:border-slate-800">
              <ShoppingBag className="mx-auto mb-8 text-slate-200" size={80} />
